function isBlacklisted(topic, pattern) {
    // Split both into parts
    const topicParts = topic.split('/');
    const patternParts = pattern.split('/');

    for (let i = 0; i < patternParts.length; i++) {
        const patternPart = patternParts[i];
        const topicPart = topicParts[i];

        if (patternPart === '#') {
            // # matches everything remaining - always true
            return true;
        }

        if (topicPart === undefined) {
            // Topic is shorter than pattern - no match
            return false;
        }

        if (patternPart === '+') {
            // + matches exactly one level - continue
            continue;
        }

        if (patternPart !== topicPart) {
            // Literal mismatch - no match
            return false;
        }
    }

    // Pattern exhausted - match only if topic is also exhausted
    return topicParts.length === patternParts.length;
}

// Check if topic matches any blacklist entry
const blocked = blacklist.some(pattern => isBlacklisted(topic, pattern));

// If blocked, return null (silently drop message)
// If not blocked, pass message through
return blocked ? null : msg;

