const arr = msg.payload;

// Default values
msg.retry = false;
msg.extracted = null;

let queueIndex = -1;

for (let i = 0; i < arr.length; i++) {
    if (typeof arr[i] === 'string') {
        if (arr[i].startsWith('queue-')) {
            queueIndex = i;
        } else if (arr[i].startsWith('wait-')) {
            if (i > 0) {
                const waitHref = arr[i - 1];

                // Find attempt value
                let attemptValue = 0;
                const attemptIndex = arr.indexOf('attempt');
                if (attemptIndex !== -1 && attemptIndex + 1 < arr.length) {
                    attemptValue = parseInt(arr[attemptIndex + 1]) || 0;
                }

                // Check if error-nocache exists
                const hasErrorNoCache = arr.includes('error-nocache');

                // Check if we should retry
                const shouldRetry = attemptValue <= 6 && !hasErrorNoCache;

                if (shouldRetry) {
                    msg.retry = true;
                    if (attemptIndex !== -1) {
                        arr[attemptIndex + 1] = attemptValue + 1;
                        msg.delay = 5 * attemptValue;
                    }
                    arr[i] = arr[i].replace('wait-', 'queue-');
                    msg.extracted = waitHref;
                }

                break; // Exit loop after processing first wait-
            }
        }
    }
}

// Always convert queue- to error-
if (queueIndex !== -1) {
    arr[queueIndex] = arr[queueIndex].replace('queue-', 'error-');
}

msg.payload = arr;
return msg;

